"use strict";parserFactory.register("systemtranslation.com",()=>new SystemTranslationParser);class SystemTranslationParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.eplisterfull ul");return util.hyperlinksToChapterList(t).reverse()}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.thumb")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"p.has-text-align-center"),super.removeUnwantedElementsFromContentElement(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.entry-content p:not(.has-text-align-center)")]}}